import styles from "../css/App.module.css";
import searchStyles from "../css/Search.module.css";
import Menubar from "../components/Menubar";
import Title from "../components/Title";
import Productcomponent from "../components/Productcomponent";
import SearchBar from "../components/SearchBar";
import { useState, useEffect } from "react";
import axios from "axios";

const TEST_PRODUCTS = [
  {
    _id: 'test1',
    title: '버니 키링 공구',
    price: 4500,
    mainPhoto: 'https://placehold.co/300x300/FFB6C1/333333?text=Bunnies+Keyring',
    startDate: '2026-03-01',
    finishDate: '2026-04-01',
    min_count: 30,
    category: '기타',
    content: '버니 아크릴 키링 공동구매입니다.',
    writer: 'bunny_lover'
  },
  {
    _id: 'test2',
    title: '과잠 맞춤 제작 (컴공 24학번)',
    price: 35000,
    mainPhoto: 'https://placehold.co/300x300/1E3A5F/ffffff?text=CS+24+Jacket',
    startDate: '2026-03-10',
    finishDate: '2026-04-15',
    min_count: 40,
    category: '의류',
    content: '컴퓨터공학과 24학번 과잠 공동구매',
    writer: 'cs_student'
  },
  {
    _id: 'test3',
    title: '스터디 플래너 노트 (6개월용)',
    price: 8900,
    mainPhoto: 'https://placehold.co/300x300/87CEEB/333333?text=Study+Planner',
    startDate: '2026-03-05',
    finishDate: '2026-04-20',
    min_count: 50,
    category: '문구류',
    content: '6개월 스터디 플래너 공동구매, 커스텀 커버 가능',
    writer: 'planner_queen'
  }
];

function Home({product}) {
  const [main, setMain] = useState([]);
  const [searchResults, setSearchResults] = useState(null);

  function calculateDday(item) {
    let endDay = new Date(item.finishDate)
    return endDay.getTime();
  }

  function calculatedday(item) {
    let startDay = new Date(item.startDate)
    return startDay.getTime();
  }

  const handleSearchResults = (results) => {
    setSearchResults(results);
  };

  const clearSearch = () => {
    setSearchResults(null);
  };

  useEffect(() => {
    const allProducts = product.length > 0 ? product : TEST_PRODUCTS;
    allProducts.sort((a, b) => new Date(a.finishDate) - new Date(b.finishDate));

    const today = new Date();
    const ctoday = today.getTime();

    let mainDdayfilter = allProducts.filter((item) => {
      return (calculateDday(item) >= ctoday) && (calculatedday(item) <= ctoday);
    })

    setMain(mainDdayfilter);

  }, [product])

  // 검색 결과가 있을 때 표시할 상품 목록
  const displayProducts = searchResults !== null ? searchResults : main;

  return(
      <div className={styles.root}>
        <div className={styles.menugrid}><Menubar /></div>
        <div className={styles.content}>
          <Title />
          <SearchBar onSearchResults={handleSearchResults} />

          {searchResults !== null && (
            <div style={{ textAlign: 'center', marginBottom: '10px' }}>
              <span className={searchStyles.searchResultsTitle}>
                검색 결과 ({searchResults.length}건)
              </span>
              <button onClick={clearSearch} style={{
                marginLeft: '10px',
                padding: '5px 15px',
                border: '1px solid #0D2D84',
                borderRadius: '15px',
                background: 'transparent',
                color: '#0D2D84',
                cursor: 'pointer',
                fontFamily: 'content'
              }}>전체보기</button>
            </div>
          )}

          {displayProducts.length !== 0 ? displayProducts.map((item) =>
            <Productcomponent key={item._id || item.id}
             main={item}
            />
          ) : <div className={styles.notice}>
                {searchResults !== null ? '검색 결과가 없습니다.' : '아직 등록된 상품이 없습니다.'}
              </div>
          }
        </div>
      </div>
    )
}

export default Home;
